import React, { useState } from 'react';
import { Users, Flag, Settings, Trash2, UserCheck, Save, AlertTriangle } from 'lucide-react';

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState('users');

  return (
    <div className="p-10 max-w-7xl mx-auto space-y-8">
      {/* HEADER */}
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter uppercase">Admin Panel</h1>
          <p className="text-slate-400 font-bold text-xs tracking-widest mt-1 uppercase">System Management</p>
        </div>
        
        {/* TAB SWITCHER */}
        <div className="flex bg-white p-2 rounded-[24px] shadow-sm border border-slate-100">
          {['users', 'reports', 'settings'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-8 py-2.5 rounded-[18px] font-black text-[10px] uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      {/* MAIN CONTENT CARD */}
      <div className="bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm min-h-[600px]">
        
        {/* USERS TAB */}
        {activeTab === 'users' && (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-800">User Directory</h3>
              <div className="p-4 bg-teal-50 text-teal-600 rounded-2xl"><Users size={24}/></div>
            </div>
            <table className="w-full">
              <thead>
                <tr className="text-left text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="pb-4 px-4">Member</th>
                  <th className="pb-4 px-4">Status</th>
                  <th className="pb-4 px-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                <tr className="group">
                  <td className="py-5 px-4 font-bold text-slate-700">Gouri <br/><span className="text-[10px] text-slate-400">gouri@wertech.com</span></td>
                  <td className="py-5 px-4"><span className="px-3 py-1 bg-teal-50 text-teal-600 text-[10px] font-black rounded-full uppercase">Verified</span></td>
                  <td className="py-5 px-4 text-right space-x-2">
                    <button className="p-2 text-slate-300 hover:text-teal-600"><UserCheck size={18}/></button>
                    <button className="p-2 text-slate-300 hover:text-red-500"><Trash2 size={18}/></button>
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        )}

        {/* REPORTS TAB */}
        {activeTab === 'reports' && (
          <div className="flex flex-col items-center justify-center py-24 text-center">
            <div className="p-6 bg-amber-50 text-amber-500 rounded-full mb-6">
              <AlertTriangle size={40} />
            </div>
            <h3 className="text-xl font-black text-slate-800">No Active Reports</h3>
            <p className="text-slate-400 text-sm font-bold mt-2 italic">The community is behaving well!</p>
          </div>
        )}

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
          <div className="max-w-xl space-y-10">
            <h3 className="text-2xl font-black text-slate-800 flex items-center gap-3">
              <Settings className="text-teal-600" /> System Settings
            </h3>
            <div className="space-y-6">
              <div className="flex justify-between items-center p-6 bg-slate-50 rounded-[30px]">
                <div>
                  <p className="font-bold text-slate-800">Maintenance Mode</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">Disable all transactions</p>
                </div>
                <div className="w-12 h-6 bg-slate-200 rounded-full"></div>
              </div>
              <button className="w-full py-5 bg-teal-600 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-xl hover:bg-teal-700 transition-all">
                <Save size={18} className="inline mr-2" /> Save System Changes
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
